int calculateMaxProfit(vector<int>& stockPrices, int transactionFee) {
        int n = stockPrices.size();
        if (n == 0) return 0;

        int cash = 0;
        int hold = -stockPrices[0];

        for (int i = 1; i < n; i++) {
            // Option 1: Sell stock today (pay fee) vs Keep cash
            cash = max(cash, hold + stockPrices[i] - transactionFee);

            // Option 2: Buy stock today vs Keep holding
            hold = max(hold, cash - stockPrices[i]);
        }

        return cash;
    }

