#define MAX(a,b) ((a) > (b) ? (a) : (b))

int calculateMaxProfit(int* stockPrices, int n, int transactionFee) {
    if (n == 0) return 0;

    // Use long long to prevent potential overflow if profits accumulate significantly
    // though given constraints int is likely fine.
    int cash = 0;
    int hold = -stockPrices[0];

    for (int i = 1; i < n; i++) {
        // Transition: Either keep cash or sell stock (paying the fee)
        cash = MAX(cash, hold + stockPrices[i] - transactionFee);

        // Transition: Either keep holding or buy new stock
        hold = MAX(hold, cash - stockPrices[i]);
    }

    return cash;
}

