class Codechef {
    public static int calculateMaxProfit(int[] stockPrices, int transactionFee) {
        if (stockPrices.length == 0) return 0;

        int cash = 0;
        int hold = -stockPrices[0];

        for (int i = 1; i < stockPrices.length; i++) {
            // Update cash position: max of keeping cash OR selling current holding
            cash = Math.max(cash, hold + stockPrices[i] - transactionFee);

            // Update hold position: max of holding current OR buying new from cash
            hold = Math.max(hold, cash - stockPrices[i]);
        }

        return cash;
    }


}

