function calculateMaxProfit(stockPrices, transactionFee) {
    if (stockPrices.length === 0) return 0;

    let cash = 0;
    let hold = -stockPrices[0];

    for (let i = 1; i < stockPrices.length; i++) {
        // Maximize cash (Sell or Wait)
        cash = Math.max(cash, hold + stockPrices[i] - transactionFee);

        // Maximize hold (Buy or Wait)
        hold = Math.max(hold, cash - stockPrices[i]);
    }

    return cash;
}
